local typeofCamera = typeof(UnityEngine.Camera)
local typeofScreenShot = typeof(CS.YXUIScreenShot)
local URect = UnityEngine.Rect
local UScreen = UnityEngine.Screen
local typeOfSkeletonAnimation = typeof(Spine.Unity.SkeletonAnimation)
local typeOfSkeletonGraphic = typeof(Spine.Unity.SkeletonGraphic)
-----------------------------------------------------------------
---@class LScreenShot
local LScreenShot = LxClass("LScreenShot", nil)
------------------------------------------------------------------
LScreenShot.SHOT_LAYER = LayerMask.NameToLayer("ScreenShot")

-----------------------------------------------------------------
function LScreenShot:LScreenShot()
	self._shotRoot = nil
	self._shotWndTrans = nil
	self._shotNotchTrans = nil
	self._csShotCamera = nil

	self._uiCamera = nil

	self._renderTexture = nil

	self._csScreenShot = nil

	self._savePathFmt = "/DCIM/game/screenshots/img_%s_%s.png"
	self._rtSize = 2048
end

function LScreenShot:Create(root, uiCamera)
	self._shotRoot = root
	CS.ShowObject(root, false)

	local rootTrans = root.transform

	local shotCamera = CS.FindTrans(rootTrans, "ShotCamera")
	local shotCanvas = CS.FindTrans(rootTrans, "ShotCanvas")
	self._shotCanvasTrans = shotCanvas

	local csScreenShot = shotCamera:GetComponent(typeofScreenShot)
	if not csScreenShot then
		csScreenShot = shotCamera.gameObject:AddComponent(typeofScreenShot)
	end
	self._csScreenShot = csScreenShot

	local csShotCamera = shotCamera:GetComponent(typeofCamera)
	self._csShotCamera = csShotCamera

	local shotWndTrans = CS.FindTrans(shotCanvas,"Wnd")
	self._shotWndTrans = shotWndTrans

	--local notch = CS.FindTrans(shotCanvas,"Notch")
	--if not notch then
	--	local obj = LxResUtil.NewObject(shotWndTrans.gameObject)
	--	obj.name = "Notch"
	--	notch = obj.transform
	--	notch:SetParent(shotCanvas, false)
	--	notch:SetAsFirstSibling()
	--	notch.localScale = shotWndTrans.localScale
	--	notch.localRotation = shotWndTrans.localRotation
	--	notch.anchoredPosition = shotWndTrans.anchoredPosition
	--
	--end
	--self._shotNotchTrans = notch

	self._uiCamera = uiCamera

	local path = CS.AppPersistentDataPath() .. "screenshot/shot.png"
	self._shotPath = path
	self:ResetCameraOrthographicSize()

	return true
end

function LScreenShot:ResetCameraOrthographicSize()
	if not self._uiCamera then return end
	local uiCamera = self._uiCamera
	local shotCamera = self._csShotCamera
	shotCamera.orthographicSize = uiCamera.orthographicSize
end

function LScreenShot:CopyWndNotch()
	local wndInst = GF.FindFirstWndByName("UINotch")
	if wndInst then
		local wndTrans = wndInst:GetWndTrans()
		if wndTrans then
			local shotNotchTrans = self._shotNotchTrans
			if not shotNotchTrans then return end
			shotNotchTrans.localScale = wndTrans.localScale
			shotNotchTrans.localPosition = wndTrans.localPosition
			shotNotchTrans.anchorMin = wndTrans.anchorMin
			shotNotchTrans.anchorMax = wndTrans.anchorMax
			shotNotchTrans.pivot = wndTrans.pivot
			shotNotchTrans.offsetMin = wndTrans.offsetMin
			shotNotchTrans.offsetMax = wndTrans.offsetMax

			local rectTransList = wndInst:GetNotchList()
			for i,v in ipairs(rectTransList or {}) do
				local obj = LxResUtil.NewObject(v.gameObject)
				local trans = obj.transform
				trans:SetParent(shotNotchTrans, false)
				trans.localScale = v.localScale
				trans.localRotation = v.localRotation
				trans.anchoredPosition = v.anchoredPosition

--[[				local gRectTrans = v:GetComponent(typeRectTransform)
				local rectTrans = trans:GetComponent(typeRectTransform)
				if gRectTrans and rectTrans then
					rectTrans.anchorMin = gRectTrans.anchorMin
					rectTrans.pivot = gRectTrans.anchorMin
					rectTrans.offsetMin = gRectTrans.anchorMin
					rectTrans.offsetMax = gRectTrans.anchorMin
				end]]

				CS.UpdateChildLayer(trans, LScreenShot.SHOT_LAYER)
			end
		end
	end
end

function LScreenShot:CopyWndParamFrom(wndTrans)
	local shotWndTrans = self._shotWndTrans
	shotWndTrans.localScale = Vector3.one
	shotWndTrans.localPosition = Vector3.zero
	shotWndTrans.anchorMin = Vector2(0.5,0.5)
	shotWndTrans.anchorMax = Vector2(0.5,0.5)
	shotWndTrans.pivot = Vector2(0.5,0.5)

	if self._shareData and self._shareData.size then
		local size = self._shareData.size
		shotWndTrans.sizeDelta = Vector2(size.x,size.y)
		
	else
		shotWndTrans.sizeDelta = Vector2(wndTrans.rect.width,wndTrans.rect.height)
	end
end

function LScreenShot:CheckPhotoPermission()
	if not LNativeHelper.CheckPermissionForMedia() then
		return false
	end

	return true
end

function LScreenShot:CaptureUIScreen(wndTrans, tblUITrans, isShare, shareData,callback)
	if self._isDestroy then return end

	if self._isShoting then
		GF.ShowMessage(ccClientText(10171))
		return
	end

	self._shareData = shareData
	if isShare then
		local shotPath = nil
		if CS.IsOSAndroid() then
			shotPath = CS.AppPersistentDataPath() .. "screenshot/shot.jpg"
		end

		self._isShoting = true
		self:DoCaptureShot(wndTrans, tblUITrans, function(...)
			self:OnShotForShare(...)
			if callback then callback() end
		end, shotPath)
	else
		--截图保存到相册
		if not self:CheckPhotoPermission() then
			LNativeHelper.RequestPermissionForMedia(ccClientText(19763), ccClientText(19788), ccClientText(19789))
			if callback then callback() end
			return
		end
		self._isShoting = true
		self:DoCaptureShot(wndTrans, tblUITrans, function(...)
			if callback then callback() end
			self:OnShotForPhoto(...)
		end)
	end
end

function LScreenShot:DoCaptureShot(wndTrans, tblUITrans, callFunc, shotPath)
	CS.ShowObject(self._shotRoot, true)
	local shotWndTrans = self._shotWndTrans

	LxResUtil.DestroyChildImmediate(shotWndTrans)
	--LxResUtil.DestroyChildImmediate(self._shotNotchTrans)

	--self:CopyWndNotch()

	self:CopyWndParamFrom(wndTrans)

	--self:ResetCameraOrthographicSize()
	local transforms = {}
	if self._shareData and self._shareData.transforms then
		transforms = self._shareData.transforms
	end
	for k,v in ipairs(tblUITrans) do
		local obj = LxResUtil.NewObject(v.gameObject)
		local trans = obj.transform
		trans:SetParent(shotWndTrans, false)
		trans.localScale = v.localScale
		trans.localRotation = v.localRotation
		trans.anchoredPosition = v.anchoredPosition
		local resetTrans = transforms[obj.name]
		
		if resetTrans then
			if resetTrans.anchoredPosition then trans.anchoredPosition = resetTrans.anchoredPosition end
			if resetTrans.localScale then trans.localScale = resetTrans.localScale end
			if resetTrans.localRotation then trans.localRotation = resetTrans.localRotation end 
		end
		CS.UpdateChildLayer(trans, LScreenShot.SHOT_LAYER)
	end

	local skeletonAnimations = self._shotRoot:GetComponentsInChildren(typeOfSkeletonAnimation)
	for k=1, skeletonAnimations.Length do
		local skeletonAnimation = skeletonAnimations[k-1]
		--下面两属性获取是为了初始化 skeleton使用，不要删除
		local skeleton = skeletonAnimation.Skeleton
		local animationState = skeletonAnimation.AnimationState
		skeletonAnimation:Update(0)
	end

	skeletonAnimations = self._shotRoot:GetComponentsInChildren(typeOfSkeletonGraphic)
	for k=1, skeletonAnimations.Length do
		local skeletonAnimation = skeletonAnimations[k-1]
		if(skeletonAnimation and not skeletonAnimation.IsValid) then
			skeletonAnimation:Initialize(false)
		end
		skeletonAnimation:Update(0)
	end


	if not self._csScreenShot then return end

	--需要先设置贴图才能，Canvas的大小才会设置
	self:CreateShotRT()

	if not self._renderTexture then
		return
	end

	if self._delayTimer then
		LxTimer.DelayTimeStop(self._delayTimer)
		self._delayTimer = nil
	end
	--摄像机设置了贴图后，需要延迟一帧， canvas的大小才会刷新成正确的
	self._delayTimer = LxTimer.DelayFrameCall(function()
		self._delayTimer = nil
		if self._isDestroy then
			return
		end
		self:CalcShotScale()
		self:CalcShotSize()
		local rect = URect.New(self._offset.x, self._offset.y, self._shotWidth, self._shotHeight)
		self._csScreenShot:CaptureScreen(rect, false, shotPath or self._shotPath, callFunc)
	end)
end

------------------------------------------------------------------
function LScreenShot:DoResetShot()
	--printErrorN("shot DoResetShot")
	self:ClearShotRT()
	LxResUtil.DestroyChildImmediate(self._shotWndTrans)
	--LxResUtil.DestroyChildImmediate(self._shotNotchTrans)
	CS.ShowObject(self._shotRoot, false)
	self._isShoting = false
end

function LScreenShot:OnShotForShare(bOk, shotFileName)
	--printErrorN("shot for share 截图分享成功")
	local nowdata = self._shareData
	if bOk and not string.isempty(shotFileName) then
		if gLSdkImpl then
			local shareData = self:GetShareData(nowdata.shareScene, shotFileName, nowdata.shareLocation, nowdata.tags)
			gLSdkImpl:CallMethod(LSdkMethod.Share,shareData)
		end
	end
	self:DoResetShot()
end

function LScreenShot:GetShareData(shareScene, imagePath, shareLocation, tags)
	---@type LShareData
	local LShareData = LxRequire("LApp.Models.Data.LShareData")
	local shareData = LShareData.GenerateShareImageData(shareScene, imagePath, shareLocation, tags)
	return shareData
end


function LScreenShot:OnShotForPhoto(bOk, shotFileName)
	--LogWarn("OnShotForPhoto bOk="..tostring(bOk)..tostring(" fileName=")..tostring(shotFileName))

	if bOk and not string.isempty(shotFileName) then
		local time = os.time()
		local rand = math.random(1, 10000)
		local destPath = string.format(self._savePathFmt, tostring(time), tostring(rand))
		LNativeHelper.SavePngToPhoto(shotFileName, destPath, "")
		if CS.IsOsWinOrEdit() then
			self:OnScreenShotResult(true)
		end

	end

	self:DoResetShot()
end

function LScreenShot:OnScreenShotResult(isOk)
	if isOk then
		GF.ShowMessage(ccClientText(10144))
		FireEvent(EventNames.INVITE_SCREEN_SHOT_OK)
	end
end
-----------------------------------------------------------------
function LScreenShot:ClearShotRT()
	if self._csShotCamera then
		self._csShotCamera.targetTexture = nil
		self._csShotCamera.enabled = false
	end
	if self._renderTexture then
		if CS.IsValidObject(self._renderTexture) then
			LRTHelper.ReleaseTemporary(self._renderTexture)
		end
		self._renderTexture = nil
	end
end

---截屏是用摄像机拍摄，摄像机的目标是一张贴图时，摄像机只会按照canvas设定的分辨率进行拍摄
---canvas 640x1136 的分辨率expand模式，摄像机能看到的范围是canvas的大小范围
---下面的逻辑根据以上现象来计算
---贴图的大小为2048，_rtSize 指定
function LScreenShot:CalcShotScale()
	local screenWidth = UScreen.width
	local screenHeight = UScreen.height

	local designWidth = LGameQuality.SCREEN_WIDTH_DESIGN-- 设计分辨率
	local designHeight = LGameQuality.SCREEN_HEIGHT_DESIGN-- 设计分辨率

	local designRate = designHeight/designWidth
	local nowRate = screenHeight/ screenWidth

	local canvasHeight = self._shotCanvasTrans.rect.height

	--实际高度大于canvas高度，需要缩小至能看全实际高度
	--小于canvas高度则放大vans高度则放大
	local shotScale = 1
	if designRate < nowRate then
		shotScale = canvasHeight / (designWidth * nowRate)
	end
	self._shotScale = shotScale

	self._shotWndTrans.localScale = Vector3(shotScale,shotScale,shotScale)

	self._scaleWndToTex = self._rtSize / canvasHeight -- canvas映射到贴图的缩放比
end

function LScreenShot:CalcShotSize()
	local sizeDelta = self._shotWndTrans.sizeDelta

	local shotScale = self._shotScale or 1
	local scaleWndToTex = self._scaleWndToTex or 1

	local readW = math.floor( sizeDelta.x * shotScale * scaleWndToTex)
	local readH = math.floor(sizeDelta.y * shotScale * scaleWndToTex)

	if readW % 2 == 1 then
		readW = readW - 1
	end
	if readH % 2 == 1 then
		readH = readH - 1
	end

	local offsetx = math.floor(2048 - readW) / 2
	local offsety = math.floor(2048 - readH) / 2

	self._shotWidth = readW
	self._shotHeight = readH

	self._offset = Vector2(offsetx , offsety)
end

function LScreenShot:CreateShotRT()
	self:ClearShotRT()

	local width = self._rtSize
	local height = self._rtSize

	local rt = LRTHelper.GetTemporary("shot_"..width.."_"..height,width,height, nil, nil, nil, nil, nil, true)
	self._renderTexture = rt

	if self._csShotCamera then
		self._csShotCamera.targetTexture = rt
		self._csShotCamera.enabled = true
	end
end

function LScreenShot:Destroy()
	if self._isDestroy then return end
	self:ClearShotRT()
	LxResUtil.DestroyChildImmediate(self._shotWndTrans)
	if self._delayTimer then
		LxTimer.DelayTimeStop(self._delayTimer)
		self._delayTimer = nil
	end
	--LxResUtil.DestroyChildImmediate(self._shotNotchTrans)
	table.removeall(self)
	self._isDestroy = true
end

return LScreenShot